  `id` bigint NOT NULL AUTO_INCREMENT,
  `external_id` varchar(255) DEFAULT NULL,
  `source_code` varchar(64) DEFAULT NULL,
  `list_type` enum('SANCTIONS','PEP','CRIME','DEBARMENT','OTHER') DEFAULT NULL,
  `list_name` enum('OFAC','EU','UN','HMT') DEFAULT NULL,
  `entry_name` varchar(500) NOT NULL,
  `entry_type` enum('INDIVIDUAL','ENTITY') NOT NULL,
  `schema_type` varchar(40) DEFAULT NULL,
  `aliases` json DEFAULT NULL,
  `topics` json DEFAULT NULL,
  `country` varchar(3) DEFAULT NULL,
  `nationalities` json DEFAULT NULL,
  `date_of_birth` date DEFAULT NULL,
  `additional_info` json DEFAULT NULL,
  `last_updated` timestamp NOT NULL,
  `last_seen_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_sanctions_external_id` (`external_id`),
  KEY `idx_sanctions_list_name` (`list_name`),
  KEY `idx_sanctions_entry_name` (`entry_name`),
