INSERT INTO `monitoring_rules` VALUES (1,'High Velocity','VELOCITY','{\"windowHours\": 24, \"maxTransactions\": 5}','MEDIUM',1,'2026-05-06 13:21:41','2026-05-06 13:21:41');
INSERT INTO `monitoring_rules` VALUES (2,'Large Transaction','AMOUNT_THRESHOLD','{\"currency\": \"GBP\", \"threshold\": 5000}','HIGH',1,'2026-05-06 13:21:41','2026-05-06 13:21:41');
INSERT INTO `monitoring_rules` VALUES (3,'Structuring Detection','STRUCTURING','{\"count\": 3, \"variance\": 500, \"threshold\": 5000, \"windowHours\": 48}','HIGH',1,'2026-05-06 13:21:41','2026-05-06 13:21:41');
INSERT INTO `monitoring_rules` VALUES (4,'High Risk Corridor','CORRIDOR_RISK','{\"highRiskCountries\": [\"IRN\", \"PRK\", \"SYR\", \"AFG\", \"YEM\"]}','CRITICAL',1,'2026-05-06 13:21:41','2026-05-06 13:21:41');
INSERT INTO `monitoring_rules` VALUES (5,'New Customer Large Transfer','AMOUNT_THRESHOLD','{\"currency\": \"GBP\", \"threshold\": 1000, \"newCustomerDays\": 30}','MEDIUM',1,'2026-05-06 13:21:41','2026-05-06 13:21:41');
INSERT INTO `monitoring_rules` VALUES (6,'Baseline Anomaly (5x rolling 30d avg)','BASELINE_ANOMALY','{\"multiplier\": 5, \"windowDays\": 30, \"minBaselineCount\": 3}','HIGH',1,'2026-05-06 13:21:41','2026-05-06 13:21:41');
INSERT INTO `monitoring_rules` VALUES (7,'Round-Number Send (multiples of 1000)','ROUND_NUMBER','{\"minAmount\": 1000, \"denominations\": [1000, 5000, 10000]}','LOW',1,'2026-05-06 13:21:41','2026-05-06 13:21:41');
INSERT INTO `monitoring_rules` VALUES (8,'Rapid Succession (two sends within 60s)','RAPID_SUCCESSION','{\"windowSeconds\": 60}','MEDIUM',1,'2026-05-06 13:21:41','2026-05-06 13:21:41');
