INSERT INTO `notification_templates` VALUES (1,'TX_CREATED','EMAIL','en','Transfer Created - {{referenceNumber}}','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#1B3571;margin:0 0 16px;font-size:20px;\">Transfer Created</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Your transfer <strong>{{referenceNumber}}</strong> has been created.</p><table style=\"width:100%;background:#f8f9fb;border-radius:8px;padding:16px;margin:16px 0;\" cellpadding=\"8\"><tr><td style=\"color:#718096;font-size:13px;\">You Send</td><td style=\"text-align:right;font-weight:600;color:#1B3571;\">{{sendAmount}} {{sendCurrency}}</td></tr><tr><td style=\"color:#718096;font-size:13px;\">Recipient Gets</td><td style=\"text-align:right;font-weight:600;color:#059669;\">{{receiveAmount}} {{receiveCurrency}}</td></tr><tr><td style=\"color:#718096;font-size:13px;\">Recipient</td><td style=\"text-align:right;font-weight:500;\">{{beneficiaryName}}</td></tr><tr><td style=\"color:#718096;font-size:13px;\">Rate</td><td style=\"text-align:right;font-family:monospace;\">{{exchangeRate}}</td></tr><tr><td style=\"color:#718096;font-size:13px;\">Fee</td><td style=\"text-align:right;\">{{feeAmount}} {{feeCurrency}}</td></tr></table><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (2,'TX_PENDING','EMAIL','en','Transfer Pending - {{referenceNumber}}','Dear {{firstName}},\n\nYour transfer {{referenceNumber}} is now pending processing.\n\nWe will notify you once your payment has been received.\n\nThank you for using Remitz.',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (3,'TX_COMPLIANCE_HOLD','EMAIL','en','Transfer Under Review - {{referenceNumber}}','Dear {{firstName}},\n\nYour transfer {{referenceNumber}} is currently under review by our compliance team. This is a routine check and we will update you shortly.\n\nThank you for your patience.',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (4,'TX_PROCESSING','EMAIL','en','Transfer Processing - {{referenceNumber}}','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#1B3571;margin:0 0 16px;font-size:20px;\">Transfer Processing</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Your payment for transfer <strong>{{referenceNumber}}</strong> has been received and is now being processed.</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">We will notify you when the funds are delivered to your recipient.</p><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (5,'TX_FUNDS_RECEIVED','EMAIL','en','Funds Received - {{referenceNumber}}','Dear {{firstName}},\n\nWe have received your funds for transfer {{referenceNumber}}. Your transfer is being sent to our payout partner.\n\nThank you for using Remitz.',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (6,'TX_SENT_TO_PAYOUT','EMAIL','en','Transfer Sent for Payout - {{referenceNumber}}','Dear {{firstName}},\n\nYour transfer {{referenceNumber}} has been sent to our payout partner for delivery.\n\nExpected delivery: within {{deliveryTime}} hours.\n\nThank you for using Remitz.',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (7,'TX_PAID','EMAIL','en','Transfer Completed - {{referenceNumber}}','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#1B3571;margin:0 0 16px;font-size:20px;\">Transfer Completed!</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Great news! Your transfer <strong>{{referenceNumber}}</strong> has been successfully delivered.</p><div style=\"background:#ecfdf5;border-radius:8px;padding:16px;text-align:center;margin:16px 0;\"><p style=\"color:#059669;font-size:22px;font-weight:700;margin:0;\">{{receiveAmount}} {{receiveCurrency}}</p><p style=\"color:#065f46;font-size:13px;margin:4px 0 0;\">delivered to {{beneficiaryName}}</p></div><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (8,'TX_FAILED','EMAIL','en','Transfer Failed - {{referenceNumber}}','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#dc2626;margin:0 0 16px;font-size:20px;\">Transfer Failed</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Unfortunately, your transfer <strong>{{referenceNumber}}</strong> could not be completed.</p><div style=\"background:#fef2f2;border-left:4px solid #dc2626;border-radius:4px;padding:12px 16px;margin:16px 0;\"><p style=\"color:#991b1b;font-size:14px;margin:0;\"><strong>Reason:</strong> {{reason}}</p></div><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Please contact our support team for assistance.</p><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (9,'TX_CANCELLED','EMAIL','en','Transfer Cancelled - {{referenceNumber}}','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#1B3571;margin:0 0 16px;font-size:20px;\">Transfer Cancelled</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Your transfer <strong>{{referenceNumber}}</strong> has been cancelled as requested.</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">If you did not request this cancellation, please contact us immediately.</p><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (10,'TX_REFUNDED','EMAIL','en','Transfer Refunded - {{referenceNumber}}','Dear {{firstName}},\n\nYour transfer {{referenceNumber}} has been refunded. {{refundAmount}} {{refundCurrency}} will be returned to your original payment method.\n\nThank you for using Remitz.',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (11,'KYC_DOCUMENT_APPROVED','EMAIL','en','KYC Document Approved','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#059669;margin:0 0 16px;font-size:20px;\">Document Approved</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Your <strong>{{documentType}}</strong> has been verified and approved.</p><div style=\"background:#ecfdf5;border-radius:8px;padding:16px;text-align:center;margin:16px 0;\"><p style=\"color:#059669;font-size:16px;font-weight:600;margin:0;\">&#x2705; Verification Successful</p></div><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Your account limits have been updated. You can now send higher amounts.</p><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (12,'KYC_DOCUMENT_REJECTED','EMAIL','en','KYC Document Rejected','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#dc2626;margin:0 0 16px;font-size:20px;\">Document Rejected</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Unfortunately, your <strong>{{documentType}}</strong> could not be verified.</p><div style=\"background:#fef2f2;border-left:4px solid #dc2626;border-radius:4px;padding:12px 16px;margin:16px 0;\"><p style=\"color:#991b1b;font-size:14px;margin:0;\"><strong>Reason:</strong> {{rejectionReason}}</p></div><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Please upload a clear, valid document and try again.</p><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (13,'KYC_TIER_UPGRADED','EMAIL','en','Account Upgraded - {{newTier}}','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#059669;margin:0 0 16px;font-size:20px;\">Account Upgraded!</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Congratulations! Your account has been upgraded.</p><div style=\"background:#ecfdf5;border-radius:8px;padding:20px;text-align:center;margin:16px 0;\"><p style=\"color:#065f46;font-size:13px;margin:0 0 4px;\">Your new tier</p><p style=\"color:#059669;font-size:24px;font-weight:700;margin:0;\">{{newTier}}</p></div><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">You now have access to higher transaction limits and additional features.</p><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (14,'WELCOME','EMAIL','en','Welcome to Remitz','Dear {{firstName}},\n\nWelcome to Remitz! Your account has been created successfully.\n\nTo get started, complete your identity verification to unlock higher transfer limits.\n\nThank you for choosing Remitz.',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (15,'PASSWORD_RESET','EMAIL','en','Password Reset Request','Dear {{firstName}},\n\nWe received a request to reset your password. Click the link below to set a new password:\n\n{{resetLink}}\n\nThis link expires in 1 hour. If you did not request this, please ignore this email.\n\nThank you for using Remitz.',1,'2026-05-06 13:21:42');
