INSERT INTO `notification_templates` VALUES (17,'NOSTRO_LOW_BALANCE','EMAIL','en','ALERT: Low Nostro Balance - {{currency}}','ALERT: Nostro account for {{currency}} ({{country}}) has fallen below the threshold.\n\nCurrent balance: {{currentBalance}}\nThreshold: {{threshold}}\n\nPlease arrange funding immediately.',1,'2026-05-06 13:21:42');
