INSERT INTO `notification_templates` VALUES (25,'KYC_DOCUMENT_EXPIRING','EMAIL','en','Action Required: Document Expiring Soon','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#d97706;margin:0 0 16px;font-size:20px;\">Document Expiring Soon</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Your <strong>{{documentType}}</strong> will expire on <strong>{{expiryDate}}</strong>.</p><div style=\"background:#fffbeb;border-left:4px solid #d97706;border-radius:4px;padding:12px 16px;margin:16px 0;\"><p style=\"color:#92400e;font-size:14px;margin:0;\">Please upload a new document before it expires to avoid service interruption.</p></div><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">You can upload your new document from your profile page.</p><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (26,'KYC_DOCUMENT_EXPIRED','EMAIL','en','Document Expired - Action Required','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#dc2626;margin:0 0 16px;font-size:20px;\">Document Expired</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Your <strong>{{documentType}}</strong> has expired. Your account may be restricted until you upload a valid document.</p><div style=\"background:#fef2f2;border-left:4px solid #dc2626;border-radius:4px;padding:12px 16px;margin:16px 0;\"><p style=\"color:#991b1b;font-size:14px;margin:0;\">Please upload a new document immediately to continue using our services.</p></div><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (27,'USER_VERIFIED','EMAIL','en','Account Fully Verified','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#059669;margin:0 0 16px;font-size:20px;\">You\'re Fully Verified!</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Your identity has been fully verified. You now have access to all Remitz features.</p><div style=\"background:#ecfdf5;border-radius:8px;padding:20px;text-align:center;margin:16px 0;\"><p style=\"color:#059669;font-size:40px;margin:0 0 8px;\">&#x2705;</p><p style=\"color:#065f46;font-size:16px;font-weight:600;margin:0;\">Identity Verified</p></div><table style=\"width:100%;margin:16px 0;\" cellpadding=\"6\"><tr><td style=\"color:#718096;font-size:13px;\">Transfer limit</td><td style=\"text-align:right;font-weight:600;color:#1B3571;\">Unlocked</td></tr><tr><td style=\"color:#718096;font-size:13px;\">All payment methods</td><td style=\"text-align:right;font-weight:600;color:#059669;\">Available</td></tr></table><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (28,'ACCOUNT_SUSPENDED','EMAIL','en','Account Suspended','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#dc2626;margin:0 0 16px;font-size:20px;\">Account Suspended</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Your Remitz account has been temporarily suspended.</p><div style=\"background:#fef2f2;border-left:4px solid #dc2626;border-radius:4px;padding:12px 16px;margin:16px 0;\"><p style=\"color:#991b1b;font-size:14px;margin:0;\"><strong>Reason:</strong> {{reason}}</p></div><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">During this time, you will not be able to initiate new transfers. If you believe this is an error, please contact our support team.</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Email: <a href=\"mailto:contact@remitz.com.au.au\" style=\"color:#1B3571;\">contact@remitz.com.au.au</a></p><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (29,'ACCOUNT_REACTIVATED','EMAIL','en','Account Reactivated','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#059669;margin:0 0 16px;font-size:20px;\">Account Reactivated</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Your Remitz account has been reactivated. You can now use all services as normal.</p><div style=\"background:#ecfdf5;border-radius:8px;padding:16px;text-align:center;margin:16px 0;\"><p style=\"color:#059669;font-size:16px;font-weight:600;margin:0;\">&#x2705; Your account is active</p></div><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Thank you for your patience.</p><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
INSERT INTO `notification_templates` VALUES (30,'TX_STATUS_UPDATED','EMAIL','en','Transfer Update - {{referenceNumber}}','<!DOCTYPE html><html><head><meta charset=\"UTF-8\"></head><body style=\"margin:0;padding:0;font-family:\'Segoe UI\',sans-serif;background:#f4f6f9;\"><table width=\"100%\" cellspacing=\"0\" cellpadding=\"0\" style=\"max-width:600px;margin:0 auto;padding:40px 20px;\"><tr><td style=\"background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;\"><h1 style=\"color:#fff;margin:0;font-size:24px;\">Remitz</h1></td></tr><tr><td style=\"background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);\"><h2 style=\"color:#1B3571;margin:0 0 16px;font-size:20px;\">Transfer Status Updated</h2><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Hi {{firstName}},</p><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Your transfer <strong>{{referenceNumber}}</strong> has been updated.</p><table style=\"width:100%;background:#f8f9fb;border-radius:8px;padding:16px;margin:16px 0;\" cellpadding=\"8\"><tr><td style=\"color:#718096;font-size:13px;\">Previous Status</td><td style=\"text-align:right;font-weight:500;\">{{previousStatus}}</td></tr><tr><td style=\"color:#718096;font-size:13px;\">New Status</td><td style=\"text-align:right;font-weight:600;color:#1B3571;\">{{newStatus}}</td></tr><tr><td style=\"color:#718096;font-size:13px;\">Amount</td><td style=\"text-align:right;font-family:monospace;\">{{sendAmount}} {{sendCurrency}}</td></tr><tr><td style=\"color:#718096;font-size:13px;\">Recipient</td><td style=\"text-align:right;\">{{beneficiaryName}}</td></tr></table><p style=\"color:#4a5568;font-size:15px;line-height:1.6;\">Log in to your account for full details.</p><hr style=\"border:none;border-top:1px solid #e2e8f0;margin:24px 0;\"><p style=\"color:#a0aec0;font-size:12px;text-align:center;\">Remitz — Secure International Money Transfers</p></td></tr></table></body></html>',1,'2026-05-06 13:21:42');
